from vex import verify, Monitor
from agno.agent import Agent

monitor = Monitor(project="code-gen-prod")

@verify(
    policies=[
        "code_safety", "syntax_valid", 
        "no_credentials", "dependency_safe"
    ],
    monitor=monitor
)
@monitor.track("code_generation")
def production_code_pipeline(task: str, max_iterations: int = 3):
    agent = Agent(
        name="ProdCodeAgent",
        model="anthropic/claude-3-5-sonnet-latest"
    )

    for i in range(max_iterations):
        result = agent.run(task)
        if monitor.approve(result):
            return result
    raise Exception("Code generation failed safety checks")

# Production usage
code = production_code_pipeline("Build secure auth API")
